#!/usr/bin/env bash
# mtss-framework-setup-mtss.sh — MTSS Framework Setup (MTSS/分层干预体系搭建) SOP walkthrough for 青少年心理健康教育.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="青少年心理健康教育"
WORKFLOW="MTSS Framework Setup (MTSS/分层干预体系搭建)"

usage() {
  cat <<EOF
mtss-framework-setup-mtss.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./mtss-framework-setup-mtss.sh             # interactive
  ./mtss-framework-setup-mtss.sh --dry-run
  ./mtss-framework-setup-mtss.sh --json
  ./mtss-framework-setup-mtss.sh --explain
  ./mtss-framework-setup-mtss.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "MTSS Framework Setup (MTSS/分层干预体系搭建)" 工作流。

一句话: From fragmented school support services to an integrated three-tier prevention-intervention-intensive system with data-driven decision rules for student movement between tiers.

入门 SOP 共 1 步, 失败模式自检 0 项。

相关心智模型:
  • 发展适配优先 — 青春期不是成人的缩小版: 青少年的大脑、认知和情绪发展处于独特阶段——前额叶皮层 25 岁前未完全成熟、杏仁核反应性高、同伴影响权重超越成人直觉——任何干预方案必须以发展阶段为锚点设计,而非照搬成人模型。
  • 预防优于治疗 — MTSS 三级金字塔: 心理健康教育的核心逻辑是三级预防——Tier 1 全员预防(SEL/心理课)覆盖约 80% 的学生、Tier 2 小组干预(针对筛查出的 at-risk 群体)覆盖约 15%、Tier 3 个别临床干

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "Establish MTSS leadership team (principal, counselor, school psych, SPED coordinator, grade-level teacher reps) and define shared vision that integrates academics, behavior (PBIS), and MH -- siloed teams build parallel systems that compete for resources 2. Conduct needs assessment: map existing interventions, staff capacity, and data systems; identify gaps using resource mapping tool -- building on unknown foundations creates redundancy and blind spots 3. Define Tier 1 (universal, all students: SEL curriculum, positive school climate, universal screening), Tier 2 (targeted, 10-15% of students: small-group counseling, Check-In/Check-Out, mentoring), and Tier 3 (intensive, 3-5%: individual counseling, wraparound services, community referral) -- vague tier definitions lead to arbitrary placement decisions 4. Build intervention menu for each tier: select evidence-based programs, assign staff, and allocate time blocks -- no menu means teams improvise under pressure 5. Establish decision rules: what data triggers movement between tiers (e.g., screening score + teacher nomination + attendance data), who makes the decision (MTSS team), and what timeline (review every 6-8 weeks) -- without decision rules, students languish in wrong tier 6. Set up data infrastructure: integrate screening data, progress monitoring, and outcome tracking in unified platform (Panorama, Branching Minds, or district SIS) -- fragmented data prevents team-based decision making 7. Launch with fidelity: begin Tier 1 universally, activate Tier 2/3 based on screening data, and schedule biweekly MTSS team meetings to review student progress -- no meeting cadence means the system exists on paper only"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "mtss-framework-setup-mtss-walkthrough"
fi
